{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以' (can/may) to ask for permission or make a polite request. This is a standard polite form in Taiwanese Mandarin.",
      "title": "Polite Request with 可以",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When ordering at a café or shop", "When asking for permission to do something", "When making a polite request to a stranger or service staff"],
      "when_not_to_use": ["When making a direct command (use 請 instead)", "When talking to close friends (sounds too formal)"],
      "pragmatic_notes": "In Taiwan, using 可以 is very common in service settings. It shows respect and is expected when interacting with shop staff.",
      "word_order_notes": "The structure is fixed: 可以 + verb + object + 嗎. Do not place 可以 at the end.",
      "english_contrast": "English uses 'can I' or 'may I' at the beginning; Chinese uses 可以 after the subject (often omitted) and before the verb.",
      "korean_contrast": "Korean uses -을/를 주세요 or -아/어도 돼요?; Chinese uses 可以 + verb + 嗎 for permission requests.",
      "negative_examples": [
        {
          "text": "可以嗎？",
          "error": "Missing action and object; the request is incomplete."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喝咖啡可以嗎？",
          "error": "Word order is wrong; 可以 should come before the verb."
        }
      ],
      "transformation_drills": ["Change '我要一杯水' to a polite request using 可以", "Change '請給我菜單' to a question using 可以"],
      "production_drills": ["Ask for a menu politely", "Ask if you can sit here"],
      "common_error_patterns": ["Placing 可以 at the end of the sentence", "Forgetting 嗎 at the end"],
      "repair_feedback": {
        "word_order": "Put 可以 right after the subject (or start with it) and before the verb.",
        "politeness": "Using 可以 makes your request polite; avoid direct commands.",
        "vocabulary": "Use appropriate verbs like 看, 坐, 試, 拿."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' (would like) to express a desire for an object. This is softer than 要 and is common in ordering.",
      "title": "Expressing Desire with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When expressing a preference in a shop", "When making a polite request for an item"],
      "when_not_to_use": ["When asking for permission (use 可以 instead)", "When making a command (use 請 instead)"],
      "pragmatic_notes": "In Taiwan, 想要 is very common in cafés and shops. It sounds natural and polite. You can add 我 or omit it.",
      "word_order_notes": "想要 is followed directly by the object. No verb is needed between 想要 and the object.",
      "english_contrast": "English uses 'I would like' + noun; Chinese uses 想要 + noun directly.",
      "korean_contrast": "Korean uses -을/를 원하다 or -고 싶다; Chinese uses 想要 + object.",
      "negative_examples": [
        {
          "text": "想要喝咖啡",
          "error": "想要 should be followed by an object, not a verb phrase. Use 想喝 instead."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想要一杯水喝",
          "error": "Adding 喝 after the object is redundant; 想要 already implies desire."
        }
      ],
      "transformation_drills": ["Change '我要一杯咖啡' to a softer request using 想要", "Change '我想喝紅茶' to use 想要"],
      "production_drills": ["Order a drink using 想要", "Say you want a bag"],
      "common_error_patterns": ["Using 想要 with a verb instead of an object", "Adding extra verbs after the object"],
      "repair_feedback": {
        "word_order": "Place 想要 directly before the object you want.",
        "politeness": "想要 is softer than 要; use it for polite ordering.",
        "vocabulary": "Use nouns like 咖啡, 茶, 水, 袋子."
      }
    },
    {
      "pattern": "不好意思 + [request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' (excuse me / sorry) as a polite softener before making a request. It shows consideration and is very common in Taiwan.",
      "title": "Polite Softener 不好意思",
      "meaning": "Excuse me, but... / Sorry to bother you, but...",
      "when_to_use": ["When starting a request to a stranger", "When interrupting someone", "When asking for help in a shop or café"],
      "when_not_to_use": ["When talking to close friends (sounds too formal)", "When making a direct command without a request"],
      "pragmatic_notes": "In Taiwan, 不好意思 is used more often than 對不起 for minor inconveniences. It softens the request and shows politeness.",
      "word_order_notes": "不好意思 comes at the beginning of the sentence, followed by the request. It can be used alone as 'excuse me'.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry' at the beginning; Chinese uses 不好意思 similarly.",
      "korean_contrast": "Korean uses 실례합니다 or 죄송합니다; Chinese uses 不好意思.",
      "negative_examples": [
        {
          "text": "不好意思，可以給我菜單嗎？",
          "error": "This is actually correct! No negative example needed."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思我要一杯水",
          "error": "Missing a polite request after 不好意思; it should be followed by a request like 可以...嗎 or 請...。"
        }
      ],
      "transformation_drills": ["Add 不好意思 to a direct request", "Change '請給我菜單' to start with 不好意思"],
      "production_drills": ["Politely ask for a menu using 不好意思", "Politely ask for the price"],
      "common_error_patterns": ["Using 不好意思 without a following request", "Using 不好意思 in very formal situations (use 抱歉 instead)"],
      "repair_feedback": {
        "word_order": "Place 不好意思 at the very beginning of your sentence.",
        "politeness": "Using 不好意思 makes your request more polite and considerate.",
        "vocabulary": "Follow with a polite request using 可以 or 請."
      }
    }
  ]
}
